#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // darken (decay) over uTime
    ret *= 0.98; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  vUv = (vUv*2)-1;
  vUv *= vec2(1, uTexSize.y/uTexSize.x); //Using uTexSize ensures perfect uAspect correction, even when the screen-dependent render mode is on.
  vUv = vec2(vUv.x, -vUv.y);

  // vec2 p = (fragCoord.xy * 2.0 - vUv.xy) / min(vUv.x, vUv.y);
  vec2 p = vUv;

  vec3 cPos = vec3(0.0,0.0, -3.0 * uTime);
  // vec3 cPos = vec3(0.3*sin(uTime*0.8), 0.4*cos(uTime*0.3), -6.0 * uTime);
  vec3 cDir = normalize(vec3(0.0, 0.0, -1.0));

  vec3 cUp  = vec3(sin(uTime), 1.0, 0.0);
  vec3 cSide = cross(cDir, cUp);
  vec3 ray = normalize(cSide * p.x + cUp * p.y + cDir);

  // Phantom Mode https://www.shadertoy.com/view/MtScWW by aiekick
  float acc = 0.0;
  float acc2 = 0.0;
  float t = 0.0;
  for (int i = 0; i < 99; i++) {
    vec3 pos = cPos + ray * t;
    float dist = map(pos, cPos);
    dist = max(abs(dist), 0.02);
    float a = exp(-dist*3.0);
    if (mod_conv(length(pos)+(bpm_pos*30), 30.0) < 3.0) {
      a *= 2.0;
      acc2 += a;
    }
    acc += a;
    t += dist * 0.5;
  }

  vec3 col = vec3(acc * 0.01, acc * 0.011 + acc2*0.002, acc * 0.012+ acc2*0.005);
  vec3 fragColor = vec4(col, 1.0 - t * 0.03);
  ret = fragColor;

  fragColor = ret;
}
